Bash(screenshot-extra.mjs << 'SCRIPT'
import { chromium } from 'playwright';

const pages = [
  { name: 'compare-lemonsqueezy-vs-stripe', url: 'http://localhost:4321/compare/lemonsqueezy-vs-stripe' },
  { name: 'blog-baas', url: 'http://localhost:4321/blog/best-backend-as-a-service-2026' },
  { name: 'blog-website-builders', url: 'http://localhost:4321/blog/best-website-builders-solo-founders' },
  { name: 'blog-ghost-vs-wp', url: 'http://localhost:4321/blog/ghost-vs-wordpress-vs-substack' },
];

const browser = await chromium.launch\({ 
  args: ['--no-sandbox', '--disable-setuid-sandbox'],
  headless: true
}\);

const context = await browser.newContext\({ viewport: { width: 1280, height: 900 } }\);

for \(const p of pages\) {
  const page = await context.newPage\(\);
  try {
    await page.goto\(p.url, { waitUntil: 'networkidle', timeout: 15000 }\);
    await page.screenshot\({ path: `/tmp/screenshots/${p.name}.png`, fullPage: true }\);
    console.log\(`OK: ${p.name}`\);
  } catch \(e\) {
    console.log\(`FAIL: ${p.name} - ${e.message}`\);
  }
  await page.close\(\);
}

await browser.close\(\);
console.log\('Done'\);
SCRIPT)
